module float_multi(
    input clk,
    input rst,
    input [31:0] a,
    input [31:0] b,
    output reg [31:0] z
);

    reg [2:0] counter;
    reg [23:0] a_mantissa, b_mantissa, z_mantissa;
    reg [9:0] a_exponent, b_exponent, z_exponent;
    reg a_sign, b_sign, z_sign;
    reg [49:0] product;
    reg guard_bit, round_bit, sticky;

    always @(posedge clk) begin
        if (rst) begin
            counter <= 0;
            z <= 0;
        end else begin
            case (counter)
                0: begin
                    // Extract fields
                    a_sign <= a[31];
                    b_sign <= b[31];
                    a_exponent <= {2'b00, a[30:23]};
                    b_exponent <= {2'b00, b[30:23]};
                    a_mantissa <= {1'b1, a[22:0]};
                    b_mantissa <= {1'b1, b[22:0]};
                    z_sign <= a[31] ^ b[31];
                    counter <= 1;
                end
                1: begin
                    // Handle special cases
                    // NaN check
                    if ((a_exponent[7:0] == 8'hFF && a_mantissa[22:0] != 0) ||
                        (b_exponent[7:0] == 8'hFF && b_mantissa[22:0] != 0)) begin
                        z <= 32'h7FC00000; // NaN
                        counter <= 0;
                    end
                    // Infinity
                    else if (a_exponent[7:0] == 8'hFF || b_exponent[7:0] == 8'hFF) begin
                        // Check for 0 * inf
                        if ((a_exponent[7:0] == 0 && a_mantissa[22:0] == 0) ||
                            (b_exponent[7:0] == 0 && b_mantissa[22:0] == 0)) begin
                            z <= 32'h7FC00000; // NaN
                        end else begin
                            z <= {z_sign, 8'hFF, 23'h0}; // Infinity
                        end
                        counter <= 0;
                    end
                    // Zero
                    else if ((a_exponent[7:0] == 0) || (b_exponent[7:0] == 0)) begin
                        z <= {z_sign, 31'h0};
                        counter <= 0;
                    end
                    else begin
                        // Multiply mantissas
                        product <= a_mantissa * b_mantissa;
                        z_exponent <= a_exponent + b_exponent - 127;
                        counter <= 2;
                    end
                end
                2: begin
                    // Normalize
                    if (product[47]) begin
                        z_mantissa <= product[46:23];
                        guard_bit <= product[22];
                        round_bit <= product[21];
                        sticky <= |product[20:0];
                        z_exponent <= z_exponent + 1;
                    end else begin
                        z_mantissa <= product[45:22];
                        guard_bit <= product[21];
                        round_bit <= product[20];
                        sticky <= |product[19:0];
                    end
                    counter <= 3;
                end
                3: begin
                    // Rounding
                    if (guard_bit && (round_bit | sticky | z_mantissa[0])) begin
                        z_mantissa <= z_mantissa + 1;
                        if (z_mantissa == 24'hFFFFFF) begin
                            z_exponent <= z_exponent + 1;
                        end
                    end
                    counter <= 4;
                end
                4: begin
                    // Check overflow/underflow and generate output
                    if ($signed(z_exponent) >= 255) begin
                        // Overflow -> Infinity
                        z <= {z_sign, 8'hFF, 23'h0};
                    end else if ($signed(z_exponent) <= 0) begin
                        // Underflow -> Zero
                        z <= {z_sign, 31'h0};
                    end else begin
                        z <= {z_sign, z_exponent[7:0], z_mantissa[22:0]};
                    end
                    counter <= 0;
                end
                default: counter <= 0;
            endcase
        end
    end

