    parameter S0 = 3'd0; // idle
    parameter S1 = 3'd1; // got 1
    parameter S2 = 3'd2; // got 10
    parameter S3 = 3'd3; // got 100
    parameter S4 = 3'd4; // got 1001
    parameter S5 = 3'd5; // got 10011

    always @(posedge CLK or posedge RST) begin
        if (RST)
            state <= S0;
        else
            state <= next_state;
    end

    always @(*) begin
        case (state)
            S0: next_state = IN ? S1 : S0;
            S1: next_state = IN ? S1 : S2;
            S2: next_state = IN ? S1 : S3;
            S3: next_state = IN ? S4 : S0;
            S4: next_state = IN ? S5 : S2;
            S5: next_state = IN ? S1 : S2;
            default: next_state = S0;
        endcase
    end

    assign MATCH = (state == S4 && IN == 1) ? 1 : 0;

endmodule

