module sequence_detector(
    input clk,
    input reset_n,
    input data_in,
    output sequence_detected,
    output IDLE,
    output S1,
    output S2,
    output S3,
    output S4
);

    reg [4:0] state, next_state;

    localparam IDLE_S = 5'b00001;
    localparam S1_S   = 5'b00010;
    localparam S2_S   = 5'b00100;
    localparam S3_S   = 5'b01000;
    localparam S4_S   = 5'b10000;

    always @(posedge clk or negedge reset_n) begin
        if (!reset_n)
            state <= IDLE_S;
        else
            state <= next_state;
    end

    always @(*) begin
        case (state)
            IDLE_S: next_state = data_in ? S1_S : IDLE_S;
            S1_S:   next_state = data_in ? S1_S : S2_S;
            S2_S:   next_state = data_in ? S1_S : S3_S;
            S3_S:   next_state = data_in ? S4_S : IDLE_S;
            S4_S:   next_state = data_in ? S1_S : S2_S;
            default: next_state = IDLE_S;
        endcase
    end

    assign sequence_detected = (state == S4_S);
    assign IDLE = (state == IDLE_S);
    assign S1   = (state == S1_S);
    assign S2   = (state == S2_S);
    assign S3   = (state == S3_S);
    assign S4   = (state == S4_S);

endmodule

