module LIFObuffer(
    input [3:0] dataIn,
    input RW,
    input EN,
    input Rst,
    input Clk,
    output reg EMPTY,
    output reg FULL,
    output reg [3:0] dataOut
);

    reg [3:0] stack_mem [0:3];
    reg [2:0] SP;
    integer i;

    always @(posedge Clk) begin
        if (EN) begin
            if (Rst) begin
                SP <= 4;
                dataOut <= 0;
                for (i = 0; i < 4; i = i + 1)
                    stack_mem[i] <= 0;
                EMPTY <= 1;
                FULL <= 0;
            end else begin
                if (RW == 0 && !FULL) begin
                    SP <= SP - 1;
                    stack_mem[SP - 1] <= dataIn;
                end else if (RW == 1 && !EMPTY) begin
                    dataOut <= stack_mem[SP];
                    stack_mem[SP] <= 0;
                    SP <= SP + 1;
                end
                EMPTY <= (SP >= 4);
                FULL <= (SP == 0);
            end
        end
    end

endmodule

