module freq_divbyfrac(
    input clk,
    input rst_n,
    output clk_div
);

parameter MUL2_DIV_CLK = 7;

reg [2:0] cnt;
reg clk_div1, clk_div2;

// Counter
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        cnt <= 0;
    else if (cnt == MUL2_DIV_CLK - 1)
        cnt <= 0;
    else
        cnt <= cnt + 1;
end

// First divided clock (posedge based) - high for 4 cycles, low for 3 cycles
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        clk_div1 <= 0;
    else begin
        if (cnt == 0)
            clk_div1 <= 1;
        else if (cnt == 4)
            clk_div1 <= 0;
    end
end

// Second divided clock (negedge based) - phase shifted by half cycle
always @(negedge clk or negedge rst_n) begin
    if (!rst_n)
        clk_div2 <= 0;
    else begin
        if (cnt == 0)
            clk_div2 <= 1;
        else if (cnt == 3)
            clk_div2 <= 0;
    end
end

// OR the two clocks to get fractional divided clock
assign clk_div = clk_div1 | clk_div2;

endmodule

