module freq_divbyfrac(
    input clk,
    input rst_n,
    output clk_div
);

parameter MUL2_DIV_CLK = 7;

reg [2:0] counter;
reg clk_div1, clk_div2;
reg clk_div1_neg, clk_div2_neg;

// Counter
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        counter <= 0;
    else if (counter == MUL2_DIV_CLK - 1)
        counter <= 0;
    else
        counter <= counter + 1;
end

// Generate clk_div1: high for 4 cycles, low for 3 cycles
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        clk_div1 <= 0;
    else begin
        if (counter == 0)
            clk_div1 <= 1;
        else if (counter == 4)
            clk_div1 <= 0;
    end
end

// Generate clk_div2: shifted version, high for 3 cycles, low for 4 cycles
always @(posedge clk or negedge rst_n) begin
    if (!rst_n)
        clk_div2 <= 0;
    else begin
        if (counter == 3)
            clk_div2 <= 1;
        else if (counter == 6)
            clk_div2 <= 0;
    end
end

// Negative edge versions for half-period shift
always @(negedge clk or negedge rst_n) begin
    if (!rst_n) begin
        clk_div1_neg <= 0;
        clk_div2_neg <= 0;
    end else begin
        clk_div1_neg <= clk_div1;
        clk_div2_neg <= clk_div2;
    end
end

assign clk_div = clk_div1_neg | clk_div2_neg;

endmodule
